import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Closes an existing job opening.
 *
 * Payload:
 * [ openingId: number ]
 */
export class JobBoardCloseOpeningComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(openingId: number) {
        const id = Math.max(0, Math.floor(openingId || 0));

        this._data = [id];

        console.log(
            '[📤] JobBoardCloseOpeningComposer packet sent:',
            this._data
        );
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
